{"file_path": "/project/NonAsciiDigitsTest.kt", "content": "import kotlinx.datetime.*
import kotlin.test.*

class NonAsciiDigitsTest {

    @Test
    fun testRejectNonAsciiDigits() {
        // Full-width digits
        assertFailsWith<IllegalArgumentException> {
            LocalDate.parse("２０２４０９０６", LocalDate.Formats.ISO_BASIC)
        }

        // Arabic-Indic digits
        assertFailsWith<IllegalArgumentException> {
            LocalDate.parse("٢٠٢٤٠٩٠٦", LocalDate.Formats.ISO_BASIC)
        }

        // Mix of ASCII and full-width digits
        assertFailsWith<IllegalArgumentException> {
            LocalDate.parse("2０2４٠٩０６", LocalDate.Formats.ISO_BASIC)
        }

        // Devanagari digits
        assertFailsWith<IllegalArgumentException> {
            LocalDate.parse("२०२४०९०६", LocalDate.Formats.ISO_BASIC)
        }
    }

    @Test
    fun testAcceptAsciiDigits() {
        // ASCII digits should still work
        val date = LocalDate.parse("20240906", LocalDate.Formats.ISO_BASIC)
        assertEquals(LocalDate(2024, 9, 6), date)
    }

    @Test
    fun testLocalTimeWithNonAsciiDigits() {
        // Full-width digits
        assertFailsWith<IllegalArgumentException> {
            LocalTime.parse("１２３４５６", LocalTime.Formats.ISO_BASIC)
        }

        // ASCII digits should work
        val time = LocalTime.parse("123456", LocalTime.Formats.ISO_BASIC)
        assertEquals(LocalTime(12, 34, 56), time)
    }

    @Test
    fun testLocalDateTimeWithNonAsciiDigits() {
        // Full-width digits in date part
        assertFailsWith<IllegalArgumentException> {
            LocalDateTime.parse("２０２４-09-06T12:34:56", LocalDateTime.Formats.ISO)
        }

        // Full-width digits in time part
        assertFailsWith<IllegalArgumentException> {
            LocalDateTime.parse("2024-09-06T１２:34:56", LocalDateTime.Formats.ISO)
        }

        // ASCII digits should work
        val dateTime = LocalDateTime.parse("2024-09-06T12:34:56", LocalDateTime.Formats.ISO)
        assertEquals(LocalDateTime(2024, 9, 6, 12, 34, 56), dateTime)
    }
}
"}

